1	import { expect, test } from "bun:test";
2	
3	test("Bun.JSONC exists", () => {
4	  expect(Bun.JSONC).toBeDefined();
5	  expect(typeof Bun.JSONC).toBe("object");
6	  expect(typeof Bun.JSONC.parse).toBe("function");
7	});
8	
9	test("Bun.JSONC.parse handles basic JSON", () => {
10	  const result = Bun.JSONC.parse('{"name": "test", "value": 42}');
11	  expect(result).toEqual({ name: "test", value: 42 });
12	});
13	
14	test("Bun.JSONC.parse handles comments", () => {
15	  const jsonc = `{
16	    // This is a comment
17	    "name": "test",
18	    /* This is a block comment */
19	    "value": 42
20	  }`;
21	
22	  const result = Bun.JSONC.parse(jsonc);
23	  expect(result).toEqual({ name: "test", value: 42 });
24	});
25	
26	test("Bun.JSONC.parse handles trailing commas", () => {
27	  const jsonc = `{
28	    "name": "test",
29	    "value": 42,
30	  }`;
31	
32	  const result = Bun.JSONC.parse(jsonc);
33	  expect(result).toEqual({ name: "test", value: 42 });
34	});
35	
36	test("Bun.JSONC.parse handles arrays with trailing commas", () => {
37	  const jsonc = `[
38	    1,
39	    2,
40	    3,
41	  ]`;
42	
43	  const result = Bun.JSONC.parse(jsonc);
44	  expect(result).toEqual([1, 2, 3]);
45	});
46	
47	test("Bun.JSONC.parse handles complex JSONC", () => {
48	  const jsonc = `{
49	    // Configuration object
50	    "name": "my-app",
51	    "version": "1.0.0",
52	    /* Dependencies section */
53	    "dependencies": {
54	      "react": "^18.0.0",
55	      "typescript": "^5.0.0", // Latest TypeScript
56	    },
57	    "scripts": [
58	      "build",
59	      "test",
60	      "lint", // Code formatting
61	    ],
62	  }`;
63	
64	  const result = Bun.JSONC.parse(jsonc);
65	  expect(result).toEqual({
66	    name: "my-app",
67	    version: "1.0.0",
68	    dependencies: {
69	      react: "^18.0.0",
70	      typescript: "^5.0.0",
71	    },
72	    scripts: ["build", "test", "lint"],
73	  });
74	});
75	
76	test("Bun.JSONC.parse handles nested objects", () => {
77	  const jsonc = `{
78	    "outer": {
79	      // Nested comment
80	      "inner": {
81	        "value": 123,
82	      }
83	    },
84	  }`;
85	
86	  const result = Bun.JSONC.parse(jsonc);
87	  expect(result).toEqual({
88	    outer: {
89	      inner: {
90	        value: 123,
91	      },
92	    },
93	  });
94	});
95	
96	test("Bun.JSONC.parse handles boolean and null values", () => {
97	  const jsonc = `{
98	    "enabled": true, // Boolean true
99	    "disabled": false, // Boolean false
100	    "nothing": null, // Null value
101	  }`;
102	
103	  const result = Bun.JSONC.parse(jsonc);
104	  expect(result).toEqual({
105	    enabled: true,
106	    disabled: false,
107	    nothing: null,
108	  });
109	});
110	
111	test("Bun.JSONC.parse throws on invalid JSON", () => {
112	  expect(() => {
113	    Bun.JSONC.parse("{ invalid json }");
114	  }).toThrow();
115	});
116	
117	test("Bun.JSONC.parse handles empty object", () => {
118	  const result = Bun.JSONC.parse("{}");
119	  expect(result).toEqual({});
120	});
121	
122	test("Bun.JSONC.parse handles empty array", () => {
123	  const result = Bun.JSONC.parse("[]");
124	  expect(result).toEqual([]);
125	});
126	
127	test("Bun.JSONC.parse throws on deeply nested arrays instead of crashing", () => {
128	  const depth = 25_000;
129	  const deepJson = "[".repeat(depth) + "]".repeat(depth);
130	  expect(() => Bun.JSONC.parse(deepJson)).toThrow(RangeError);
131	});
132	
133	test("Bun.JSONC.parse throws on deeply nested objects instead of crashing", () => {
134	  const depth = 25_000;
135	  const deepJson = '{"a":'.repeat(depth) + "1" + "}".repeat(depth);
136	  expect(() => Bun.JSONC.parse(deepJson)).toThrow(RangeError);
137	});
