1	pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
2	    const object = JSValue.createEmptyObject(globalThis, 2);
3	    object.put(
4	        globalThis,
5	        ZigString.static("parse"),
6	        jsc.JSFunction.create(
7	            globalThis,
8	            "parse",
9	            parse,
10	            1,
11	            .{},
12	        ),
13	    );
14	    object.put(
15	        globalThis,
16	        ZigString.static("stringify"),
17	        jsc.JSFunction.create(
18	            globalThis,
19	            "stringify",
20	            stringify,
21	            3,
22	            .{},
23	        ),
