267	
268	        if (iter.len == 0) {
269	            this.builder.append(.latin1, "{}");
270	            return;
271	        }
272	
273	        this.builder.append(.lchar, '{');
274	
275	        switch (this.space) {
276	            .minified => {
277	                var first = true;
278	                while (try iter.next()) |prop_name| {
279	                    if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) {
280	                        continue;
281	                    }
282	                    if (!first) this.builder.append(.lchar, ',');
