105	        object->getOwnPropertyNames(object, globalObject, properties, DontEnumPropertiesMode::Exclude);
106	        RETURN_IF_EXCEPTION(throwScope, void());
107	
108	        auto len = properties.size() + 1;
109	        exportNames.reserveCapacity(len);
110	        exportValues.ensureCapacity(len);
111	
112	        bool hasDefault = false;
113	
114	        for (auto& entry : properties) {
115	            if (entry == vm.propertyNames->defaultKeyword) [[unlikely]] {
116	                hasDefault = true;
117	            }
118	            exportNames.append(entry);
119	            JSValue value = object->get(globalObject, entry);
