21	    pub fn get(_: std.mem.Allocator) *LinkedList.Node {
22	        if (loaded) {
23	            if (list.popFirst()) |node| {
24	                node.data.clearRetainingCapacity();
25	                return node;
26	            }
27	        }
28	
29	        const new_node = default_allocator.create(LinkedList.Node) catch unreachable;
30	        new_node.* = LinkedList.Node{ .data = HashMap.initContext(default_allocator, IdentityContext{}) };
31	        return new_node;
32	    }
33	
34	    pub fn release(node: *LinkedList.Node) void {
35	        if (loaded) {
36	            list.prepend(node);
37	            return;
38	        }
39	
40	        list = LinkedList{ .first = node };
41	        loaded = true;
