/// INI Parser
///
/// Parses INI text into an Expr AST object. Handles:
///   - [sections] as nested objects
///   - key=value (and key: value) pairs
///   - ; and # comment lines
///   - Value coercion: "true"/"false" → boolean, "null" → null, numbers → number
///   - CRLF line endings

pub const ParseError = OOM || error{SyntaxError};

/// Parse an INI source into an Expr.
///
/// The returned Expr is an `e_object` whose properties are:
///   - One property per global (section-less) key=value pair.
///   - One `e_object` property per [section], containing that section's pairs.
pub fn parse(source: *const logger.Source, log: *logger.Log, allocator: std.mem.Allocator) ParseError!Expr {
    const text = source.contents;
    const loc: logger.Loc = .{};

    // Collect global properties (before any section header)
    var global_props = std.ArrayList(G.Property).init(allocator);

    // Collect sections as ordered (name, props) pairs
    var section_names = std.ArrayList([]const u8).init(allocator);
    var section_props = std.ArrayList(std.ArrayList(G.Property)).init(allocator);

    // Index of the current section (-1 = global)
    var current_section: i64 = -1;

    var line_iter: LineIterator = .{ .text = text };
    while (line_iter.next()) |raw_line| {
        // Strip CR so CRLF and LF both work
        const line = if (raw_line.len > 0 and raw_line[raw_line.len - 1] == '\r')
            raw_line[0 .. raw_line.len - 1]
        else
            raw_line;

        // Trim leading/trailing whitespace
        const trimmed = std.mem.trim(u8, line, " \t");

        // Skip blank lines
        if (trimmed.len == 0) continue;

        // Skip comment lines
        if (trimmed[0] == ';' or trimmed[0] == '#') continue;

        // Section header: [name]
        if (trimmed[0] == '[') {
            const close = std.mem.indexOfScalar(u8, trimmed, ']') orelse {
                try log.addError(source, loc, "INI parse error: missing ']' in section header");
                return error.SyntaxError;
            };
            const name = std.mem.trim(u8, trimmed[1..close], " \t");
            const name_copy = try allocator.dupe(u8, name);
            try section_names.append(name_copy);
            try section_props.append(std.ArrayList(G.Property).init(allocator));
            current_section = @intCast(section_names.items.len - 1);
            continue;
        }

        // Key=value or key: value pair
        const sep_idx = std.mem.indexOfAny(u8, trimmed, "=:") orelse {
            // Lines without a separator are ignored
            continue;
        };

        const key_raw = std.mem.trim(u8, trimmed[0..sep_idx], " \t");
        const val_raw = std.mem.trim(u8, trimmed[sep_idx + 1 ..], " \t");

        if (key_raw.len == 0) continue;

        const key_copy = try allocator.dupe(u8, key_raw);
        const key_expr = Expr.init(E.String, E.String.init(key_copy), loc);
        const val_expr = try coerceValue(val_raw, allocator, loc);

        const prop: G.Property = .{ .key = key_expr, .value = val_expr };

        if (current_section < 0) {
            try global_props.append(prop);
        } else {
            try section_props.items[@intCast(current_section)].append(prop);
        }
    }

    // Build the root object
    var root_props = std.ArrayList(G.Property).init(allocator);

    // Global key-value pairs first
    try root_props.appendSlice(global_props.items);

    // Then one nested object per section
    for (section_names.items, section_props.items) |name, *props| {
        const section_obj = Expr.init(E.Object, .{
            .properties = G.Property.List.moveFromList(props),
        }, loc);
        const section_key = Expr.init(E.String, E.String.init(name), loc);
        try root_props.append(.{ .key = section_key, .value = section_obj });
    }

    return Expr.init(E.Object, .{
        .properties = G.Property.List.moveFromList(&root_props),
    }, loc);
}

/// Coerce a raw string value to the most appropriate Expr type.
fn coerceValue(val: []const u8, allocator: std.mem.Allocator, loc: logger.Loc) OOM!Expr {
    if (bun.strings.eqlComptime(val, "true")) return Expr.init(E.Boolean, .{ .value = true }, loc);
    if (bun.strings.eqlComptime(val, "false")) return Expr.init(E.Boolean, .{ .value = false }, loc);
    if (bun.strings.eqlComptime(val, "null")) return Expr.init(E.Null, .{}, loc);

    // Attempt numeric coercion
    if (std.fmt.parseFloat(f64, val)) |num| {
        return Expr.init(E.Number, .{ .value = num }, loc);
    } else |_| {}

    const copy = try allocator.dupe(u8, val);
    return Expr.init(E.String, E.String.init(copy), loc);
}

/// A simple line iterator that does not allocate.
const LineIterator = struct {
    text: []const u8,
    pos: usize = 0,

    pub fn next(self: *LineIterator) ?[]const u8 {
        if (self.pos >= self.text.len) return null;
        const start = self.pos;
        while (self.pos < self.text.len and self.text[self.pos] != '\n') {
            self.pos += 1;
        }
        const end = self.pos;
        if (self.pos < self.text.len) self.pos += 1; // skip '\n'
        return self.text[start..end];
    }
};

