import { describe, test, expect } from "bun:test";

describe("Bun.INI", () => {
  // ── existence ────────────────────────────────────────────────────────────

  test("Bun.INI exists as an object", () => {
    expect(Bun.INI).toBeDefined();
    expect(typeof Bun.INI).toBe("object");
  });

  test("Bun.INI.parse is a function", () => {
    expect(typeof Bun.INI.parse).toBe("function");
  });

  test("Bun.INI.stringify is a function", () => {
    expect(typeof Bun.INI.stringify).toBe("function");
  });

  // ── parse ─────────────────────────────────────────────────────────────────

  describe("parse", () => {
    test("empty string returns empty object", () => {
      expect(Bun.INI.parse("")).toEqual({});
    });

    test("blank lines are ignored", () => {
      expect(Bun.INI.parse("\n\n\n")).toEqual({});
    });

    test("semicolon comments are skipped", () => {
      expect(Bun.INI.parse("; this is a comment\nkey=value")).toEqual({ key: "value" });
    });

    test("hash comments are skipped", () => {
      expect(Bun.INI.parse("# this is a comment\nkey=value")).toEqual({ key: "value" });
    });

    test("simple key=value", () => {
      expect(Bun.INI.parse("name=Alice")).toEqual({ name: "Alice" });
    });

    test("multiple global key=value pairs", () => {
      expect(Bun.INI.parse("a=1\nb=2\nc=3")).toEqual({ a: 1, b: 2, c: 3 });
    });

    test("whitespace around key and value is trimmed", () => {
      expect(Bun.INI.parse("  key  =  value  ")).toEqual({ key: "value" });
    });

    test("boolean coercion: true", () => {
      expect(Bun.INI.parse("enabled=true")).toEqual({ enabled: true });
    });

    test("boolean coercion: false", () => {
      expect(Bun.INI.parse("debug=false")).toEqual({ debug: false });
    });

    test("null coercion", () => {
      expect(Bun.INI.parse("val=null")).toEqual({ val: null });
    });

    test("integer coercion", () => {
      expect(Bun.INI.parse("port=8080")).toEqual({ port: 8080 });
    });

    test("float coercion", () => {
      expect(Bun.INI.parse("ratio=1.5")).toEqual({ ratio: 1.5 });
    });

    test("negative number coercion", () => {
      expect(Bun.INI.parse("offset=-42")).toEqual({ offset: -42 });
    });

    test("non-numeric string stays a string", () => {
      expect(Bun.INI.parse("color=red")).toEqual({ color: "red" });
    });

    test("section header creates nested object", () => {
      const result = Bun.INI.parse("[database]\nhost=localhost\nport=5432");
      expect(result).toEqual({ database: { host: "localhost", port: 5432 } });
    });

    test("global keys before sections are at root level", () => {
      const result = Bun.INI.parse("name=myapp\n[server]\nhost=0.0.0.0");
      expect(result).toEqual({ name: "myapp", server: { host: "0.0.0.0" } });
    });

    test("multiple sections", () => {
      const ini = `
[database]
host=localhost
port=5432

[cache]
host=redis
ttl=300
`;
      expect(Bun.INI.parse(ini)).toEqual({
        database: { host: "localhost", port: 5432 },
        cache: { host: "redis", ttl: 300 },
      });
    });

    test("CRLF line endings are handled", () => {
      expect(Bun.INI.parse("a=1\r\nb=2\r\n")).toEqual({ a: 1, b: 2 });
    });

    test("colon separator is supported", () => {
      expect(Bun.INI.parse("key: value")).toEqual({ key: "value" });
    });

    test("section name is trimmed", () => {
      const result = Bun.INI.parse("[ my section ]\nkey=val");
      expect(result).toEqual({ "my section": { key: "val" } });
    });

    test("lines without separator are ignored", () => {
      expect(Bun.INI.parse("justAWord\nkey=value")).toEqual({ key: "value" });
    });

    test("mixed comments, blanks, globals, and sections", () => {
      const ini = `
; App config
app=myapp

# Server settings
[server]
port=3000
debug=false
`;
      expect(Bun.INI.parse(ini)).toEqual({
        app: "myapp",
        server: { port: 3000, debug: false },
      });
    });
  });

  // ── stringify ─────────────────────────────────────────────────────────────

  describe("stringify", () => {
    test("empty object produces empty string", () => {
      expect(Bun.INI.stringify({})).toBe("");
    });

    test("flat string values", () => {
      expect(Bun.INI.stringify({ name: "Alice" })).toBe("name=Alice\n");
    });

    test("flat number values", () => {
      expect(Bun.INI.stringify({ port: 8080 })).toBe("port=8080\n");
    });

    test("flat boolean values", () => {
      expect(Bun.INI.stringify({ enabled: true, debug: false })).toBe(
        "enabled=true\ndebug=false\n",
      );
    });

    test("null value", () => {
      expect(Bun.INI.stringify({ val: null })).toBe("val=null\n");
    });

    test("nested object becomes a section", () => {
      const result = Bun.INI.stringify({ database: { host: "localhost", port: 5432 } });
      expect(result).toBe("\n[database]\nhost=localhost\nport=5432\n");
    });

    test("global keys appear before sections", () => {
      const result = Bun.INI.stringify({
        name: "myapp",
        server: { host: "0.0.0.0", port: 3000 },
      });
      expect(result).toBe("name=myapp\n\n[server]\nhost=0.0.0.0\nport=3000\n");
    });

    test("multiple sections", () => {
      const result = Bun.INI.stringify({
        database: { host: "localhost", port: 5432 },
        cache: { host: "redis", ttl: 300 },
      });
      expect(result).toBe(
        "\n[database]\nhost=localhost\nport=5432\n\n[cache]\nhost=redis\nttl=300\n",
      );
    });

    test("throws on non-object input", () => {
      expect(() => Bun.INI.stringify("hello" as any)).toThrow();
      expect(() => Bun.INI.stringify(42 as any)).toThrow();
    });

    test("undefined and function values are skipped", () => {
      const result = Bun.INI.stringify({ a: 1, b: undefined, c: () => {} } as any);
      expect(result).toBe("a=1\n");
    });
  });

  // ── round-trip ────────────────────────────────────────────────────────────

  describe("round-trip", () => {
    test("global key-value pairs round-trip", () => {
      const original = { name: "app", port: 8080, debug: false };
      const serialized = Bun.INI.stringify(original);
      const parsed = Bun.INI.parse(serialized);
      expect(parsed).toEqual(original);
    });

    test("section round-trip", () => {
      const original = {
        database: { host: "localhost", port: 5432, ssl: true },
      };
      const serialized = Bun.INI.stringify(original);
      const parsed = Bun.INI.parse(serialized);
      expect(parsed).toEqual(original);
    });

    test("mixed global + sections round-trip", () => {
      const original = {
        app: "myapp",
        server: { host: "0.0.0.0", port: 3000 },
        cache: { ttl: 300 },
      };
      const serialized = Bun.INI.stringify(original);
      const parsed = Bun.INI.parse(serialized);
      expect(parsed).toEqual(original);
    });
  });
});

