/**
 * Tests for the Bun.INI public API namespace.
 *
 * Bun.INI.parse  — parses an INI string into a plain JS object
 * Bun.INI.stringify — serialises a plain JS object into an INI string
 */
import { describe, test, expect } from "bun:test";

declare namespace Bun {
  const INI: {
    parse(input: string): Record<string, any>;
    stringify(obj: Record<string, any>): string;
  };
}

describe("Bun.INI", () => {
  // ── existence ──────────────────────────────────────────────────────────────

  test("Bun.INI is an object", () => {
    expect(typeof Bun.INI).toBe("object");
    expect(Bun.INI).not.toBeNull();
  });

  test("Bun.INI.parse is a function", () => {
    expect(typeof Bun.INI.parse).toBe("function");
  });

  test("Bun.INI.stringify is a function", () => {
    expect(typeof Bun.INI.stringify).toBe("function");
  });

  // ── parse ──────────────────────────────────────────────────────────────────

  describe("parse", () => {
    test("empty string returns empty object", () => {
      expect(Bun.INI.parse("")).toEqual({});
    });

    test("blank lines only returns empty object", () => {
      expect(Bun.INI.parse("\n\n\n")).toEqual({});
    });

    test("semicolon comment lines are ignored", () => {
      expect(Bun.INI.parse("; comment\nkey=value")).toEqual({ key: "value" });
    });

    test("hash comment lines are ignored", () => {
      expect(Bun.INI.parse("# comment\nkey=value")).toEqual({ key: "value" });
    });

    test("simple key=value", () => {
      expect(Bun.INI.parse("name=Alice")).toEqual({ name: "Alice" });
    });

    test("multiple global key=value pairs", () => {
      expect(Bun.INI.parse("a=1\nb=2\nc=3")).toEqual({ a: 1, b: 2, c: 3 });
    });

    test("whitespace around key and value is trimmed", () => {
      expect(Bun.INI.parse("  key  =  value  ")).toEqual({ key: "value" });
    });

    test("coerces 'true' to boolean true", () => {
      expect(Bun.INI.parse("enabled=true")).toEqual({ enabled: true });
    });

    test("coerces 'false' to boolean false", () => {
      expect(Bun.INI.parse("debug=false")).toEqual({ debug: false });
    });

    test("coerces 'null' to null", () => {
      expect(Bun.INI.parse("val=null")).toEqual({ val: null });
    });

    test("coerces integer strings to numbers", () => {
      expect(Bun.INI.parse("port=8080")).toEqual({ port: 8080 });
    });

    test("coerces float strings to numbers", () => {
      expect(Bun.INI.parse("ratio=1.5")).toEqual({ ratio: 1.5 });
    });

    test("coerces negative number strings", () => {
      expect(Bun.INI.parse("offset=-42")).toEqual({ offset: -42 });
    });

    test("non-numeric strings remain strings", () => {
      expect(Bun.INI.parse("color=red")).toEqual({ color: "red" });
    });

    test("section header creates a nested object", () => {
      expect(Bun.INI.parse("[database]\nhost=localhost\nport=5432")).toEqual({
        database: { host: "localhost", port: 5432 },
      });
    });

    test("global keys before section are at root", () => {
      expect(Bun.INI.parse("name=myapp\n[server]\nhost=0.0.0.0")).toEqual({
        name: "myapp",
        server: { host: "0.0.0.0" },
      });
    });

    test("multiple sections", () => {
      const ini = "[database]\nhost=localhost\nport=5432\n\n[cache]\nhost=redis\nttl=300\n";
      expect(Bun.INI.parse(ini)).toEqual({
        database: { host: "localhost", port: 5432 },
        cache: { host: "redis", ttl: 300 },
      });
    });

    test("CRLF line endings are handled", () => {
      expect(Bun.INI.parse("a=1\r\nb=2\r\n")).toEqual({ a: 1, b: 2 });
    });

    test("colon separator is supported", () => {
      expect(Bun.INI.parse("key: value")).toEqual({ key: "value" });
    });

    test("section name whitespace is trimmed", () => {
      expect(Bun.INI.parse("[ my section ]\nkey=val")).toEqual({
        "my section": { key: "val" },
      });
    });

    test("lines without a separator are silently ignored", () => {
      expect(Bun.INI.parse("justAWord\nkey=value")).toEqual({ key: "value" });
    });

    test("mixed comments, blanks, globals, and sections", () => {
      const ini = "; App config\napp=myapp\n\n# Server settings\n[server]\nport=3000\ndebug=false\n";
      expect(Bun.INI.parse(ini)).toEqual({
        app: "myapp",
        server: { port: 3000, debug: false },
      });
    });
  });

  // ── stringify ─────────────────────────────────────────────────────────────

  describe("stringify", () => {
    test("empty object produces empty string", () => {
      expect(Bun.INI.stringify({})).toBe("");
    });

    test("string value", () => {
      expect(Bun.INI.stringify({ name: "Alice" })).toBe("name=Alice\n");
    });

    test("integer value", () => {
      expect(Bun.INI.stringify({ port: 8080 })).toBe("port=8080\n");
    });

    test("boolean values", () => {
      expect(Bun.INI.stringify({ enabled: true, debug: false })).toBe(
        "enabled=true\ndebug=false\n",
      );
    });

    test("null value", () => {
      expect(Bun.INI.stringify({ val: null })).toBe("val=null\n");
    });

    test("nested object becomes a [section] block", () => {
      expect(Bun.INI.stringify({ database: { host: "localhost", port: 5432 } })).toBe(
        "\n[database]\nhost=localhost\nport=5432\n",
      );
    });

    test("global keys appear before sections", () => {
      expect(
        Bun.INI.stringify({ name: "myapp", server: { host: "0.0.0.0", port: 3000 } }),
      ).toBe("name=myapp\n\n[server]\nhost=0.0.0.0\nport=3000\n");
    });

    test("multiple sections", () => {
      expect(
        Bun.INI.stringify({
          database: { host: "localhost", port: 5432 },
          cache: { host: "redis", ttl: 300 },
        }),
      ).toBe("\n[database]\nhost=localhost\nport=5432\n\n[cache]\nhost=redis\nttl=300\n");
    });

    test("undefined values are skipped", () => {
      expect(Bun.INI.stringify({ a: 1, b: undefined as any })).toBe("a=1\n");
    });

    test("function values are skipped", () => {
      expect(Bun.INI.stringify({ a: 1, fn: (() => {}) as any })).toBe("a=1\n");
    });

    test("throws on non-object input", () => {
      expect(() => Bun.INI.stringify("hello" as any)).toThrow();
      expect(() => Bun.INI.stringify(42 as any)).toThrow();
      expect(() => Bun.INI.stringify(null as any)).toThrow();
    });
  });

  // ── round-trip ─────────────────────────────────────────────────────────────

  describe("round-trip", () => {
    test("flat key-value pairs", () => {
      const original = { name: "app", port: 8080, debug: false };
      expect(Bun.INI.parse(Bun.INI.stringify(original))).toEqual(original);
    });

    test("single section", () => {
      const original = { database: { host: "localhost", port: 5432, ssl: true } };
      expect(Bun.INI.parse(Bun.INI.stringify(original))).toEqual(original);
    });

    test("global keys plus sections", () => {
      const original = {
        app: "myapp",
        server: { host: "0.0.0.0", port: 3000 },
        cache: { ttl: 300 },
      };
      expect(Bun.INI.parse(Bun.INI.stringify(original))).toEqual(original);
    });
  });
});

