/// Bun.INI — public API namespace
///
/// Exposes `parse` and `stringify` methods that mirror the pattern of
/// Bun.TOML, Bun.JSONC, Bun.JSON5, and Bun.YAML.

pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

// ── parse ──────────────────────────────────────────────────────────────────

pub fn parse(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    var arena: bun.ArenaAllocator = .init(bun.default_allocator);
    defer arena.deinit();
    const allocator = arena.allocator();

    var ast_memory_allocator = bun.handleOom(allocator.create(ast.ASTMemoryAllocator));
    var ast_scope = ast_memory_allocator.enter(allocator);
    defer ast_scope.exit();

    const input_value = callFrame.argument(0);

    if (input_value.isEmptyOrUndefinedOrNull()) {
        return global.throwInvalidArguments("Expected a string to parse", .{});
    }

    const input: jsc.Node.BlobOrStringOrBuffer =
        try jsc.Node.BlobOrStringOrBuffer.fromJS(global, allocator, input_value) orelse input: {
            var str = try input_value.toBunString(global);
            defer str.deref();
            break :input .{ .string_or_buffer = .{ .string = str.toSlice(allocator) } };
        };
    defer input.deinit();

    var log = logger.Log.init(bun.default_allocator);
    defer log.deinit();

    const source = &logger.Source.initPathString("input.ini", input.slice());

    const root = ini.parse(source, &log, allocator) catch |err| return switch (err) {
        error.OutOfMemory => |oom| oom,
        error.SyntaxError => {
            if (log.msgs.items.len > 0) {
                const first_msg = log.msgs.items[0];
                return global.throwValue(global.createSyntaxErrorInstance(
                    "INI Parse error: {s}",
                    .{first_msg.data.text},
                ));
            }
            return global.throwValue(global.createSyntaxErrorInstance(
                "INI Parse error: Unable to parse INI string",
                .{},
            ));
        },
    };

    return exprToJS(root, global);
}

// ── stringify ──────────────────────────────────────────────────────────────

pub fn stringify(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value = callFrame.argument(0);

    if (value.isUndefinedOrNull() or !value.isObject()) {
        return global.throwInvalidArguments("INI.stringify requires a plain object", .{});
    }

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    try stringifyObject(global, value, &builder);

    return builder.toString(global);
}

/// Writes `key=<value>` lines for non-object properties, then `[section]`
/// blocks for object-valued properties.
fn stringifyObject(
    global: *jsc.JSGlobalObject,
    obj: JSValue,
    builder: *wtf.StringBuilder,
) bun.JSError!void {
    var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
        global,
        try obj.toObject(global),
    );
    defer iter.deinit();

    // Collect section names so we can emit them after the flat pairs.
    // We iterate twice: once for flat pairs, then rebuild the iterator for sections.
    // Instead, we do a single pass and defer section emission.
    const Pair = struct { key: bun.String, val: JSValue };
    var sections = std.ArrayList(Pair).init(bun.default_allocator);
    defer {
        for (sections.items) |*p| p.key.deref();
        sections.deinit();
    }

    while (try iter.next()) |key| {
        const val = iter.value;
        if (val.isUndefined() or val.isSymbol() or val.isFunction()) continue;

        if (val.isObject() and !val.isArray()) {
            // Defer to section pass
            const key_dup = key.dupeRef();
            try sections.append(.{ .key = key_dup, .val = val });
            continue;
        }

        // Flat key=value
        try appendKey(builder, key);
        builder.append(.latin1, "=");
        try appendPrimitive(global, builder, val);
        builder.append(.lchar, '\n');
    }

    // Emit section blocks
    for (sections.items) |*pair| {
        builder.append(.lchar, '\n');
        builder.append(.lchar, '[');
        builder.append(.string, pair.key);
        builder.append(.latin1, "]\n");

        var sec_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try pair.val.toObject(global),
        );
        defer sec_iter.deinit();

        while (try sec_iter.next()) |sec_key| {
            const sec_val = sec_iter.value;
            if (sec_val.isUndefined() or sec_val.isSymbol() or sec_val.isFunction()) continue;
            // Nested objects/arrays inside sections are skipped
            if (sec_val.isObject()) continue;

            try appendKey(builder, sec_key);
            builder.append(.latin1, "=");
            try appendPrimitive(global, builder, sec_val);
            builder.append(.lchar, '\n');
        }
    }
}

fn appendKey(builder: *wtf.StringBuilder, key: bun.String) bun.JSError!void {
    builder.append(.string, key);
}

fn appendPrimitive(
    global: *jsc.JSGlobalObject,
    builder: *wtf.StringBuilder,
    val: JSValue,
) bun.JSError!void {
    if (val.isNull()) {
        builder.append(.latin1, "null");
        return;
    }
    if (val.isBoolean()) {
        builder.append(.latin1, if (val.asBoolean()) "true" else "false");
        return;
    }
    if (val.isInt32()) {
        builder.append(.int, val.asInt32());
        return;
    }
    if (val.isNumber()) {
        builder.append(.double, val.asNumber());
        return;
    }
    if (val.isString()) {
        const str = try val.toBunString(global);
        defer str.deref();
        builder.append(.string, str);
        return;
    }
    // Fallback: coerce to string
    const str = try val.toBunString(global);
    defer str.deref();
    builder.append(.string, str);
}

// ── Helpers ────────────────────────────────────────────────────────────────

/// Convert a parsed Expr back to a JS value.
fn exprToJS(expr: Expr, global: *jsc.JSGlobalObject) bun.JSError!jsc.JSValue {
    switch (expr.data) {
        .e_null => return .null,
        .e_boolean => |b| return .jsBoolean(b.value),
        .e_number => |n| return .jsNumber(n.value),
        .e_string => |s| return s.toJS(bun.default_allocator, global),
        .e_object => |obj| {
            var js_obj = JSValue.createEmptyObject(global, obj.properties.len);
            for (obj.properties.slice()) |prop| {
                const key_expr = prop.key.?;
                const val_js = try exprToJS(prop.value.?, global);
                const key_js = try exprToJS(key_expr, global);
                const key_str = try key_js.toBunString(global);
                defer key_str.deref();
                try js_obj.putMayBeIndex(global, &key_str, val_js);
            }
            return js_obj;
        },
        else => return .js_undefined,
    }
}

